      }
    }
    const linhas = list
      .map((p) => {
        let procHint = ' | procedimentos: (painel sem vГѓЖ’Г‚В­nculos ГѓВўГўвЂљВ¬Гўв‚¬Вќ nГѓЖ’Г‚ВЈo oferecer para procedimento especГѓЖ’Г‚В­fico)';
