      .join('\n');
    const procRuleBlock =
      '\n\n## REGRA ГѓВўГўвЂљВ¬Гўв‚¬Вќ PROCEDIMENTO PRIMEIRO, DEPOIS O PROFISSIONAL\n' +
      '1) **Antes de horГѓЖ’Г‚ВЎrios ou profissional**, confirme qual **procedimento/serviГѓЖ’Г‚В§o** o cliente quer: compare o que ele disse (ex.: clareamento) com **SERVIГѓЖ’Гўв‚¬ВЎOS DISPONГѓЖ’Г‚ВЌVEIS** e fixe o **servico_id** certo. ' +
      'Se nГѓЖ’Г‚ВЈo estiver claro, **pergunte** objetivamente qual procedimento deseja (pode citar 2ГѓВўГўвЂљВ¬Гўв‚¬Е“4 nomes do catГѓЖ’Г‚ВЎlogo).\n' +
      '2) ГѓвЂљГ‚В«procedimentos (servico_id): ГѓВўГўвЂљВ¬Г‚В¦ГѓвЂљГ‚В» = UUIDs cadastrados no painel; ГѓвЂљГ‚В«painel sem vГѓЖ’Г‚В­nculosГѓвЂљГ‚В» = **nГѓЖ’Г‚ВЈo** oferecer para procedimento especГѓЖ’Г‚В­fico (ex.: clareamento). ' +
      '3) Quando a mensagem **jГѓЖ’Г‚ВЎ citou** um serviГѓЖ’Г‚В§o, a lista **PROFISSIONAIS** acima (se filtrada) contГѓЖ’Г‚В©m **somente** quem realiza esse procedimento ГѓВўГўвЂљВ¬Гўв‚¬Вќ **nГѓЖ’Г‚ВЈo** cite outros profissionais da clГѓЖ’Г‚В­nica para esse serviГѓЖ’Г‚В§o. ' +
      'Use **agd_cs_consultar_vagas** com **procedimento** ou **servico_id**.\n' +
      '4) Se **sГѓЖ’Г‚Ві um** profissional for compatГѓЖ’Г‚В­vel, **nГѓЖ’Г‚ВЈo** pergunte preferГѓЖ’Г‚ВЄncia ГѓВўГўвЂљВ¬Гўв‚¬Вќ vГѓЖ’Г‚ВЎ direto ГѓЖ’Г‚В s vagas dele.\n' +
      '5) **agd_cs_consultar_vagas** / **agd_cs_agendar**: **procedimento** ou **servico_id** obrigatГѓЖ’Г‚Віrios quando o serviГѓЖ’Г‚В§o jГѓЖ’Г‚ВЎ for conhecido.\n';
    profBlock =
      '\n\n## PROFISSIONAIS DISPONГѓЖ’Г‚ВЌVEIS (use estes profissional_id ГѓВўГўвЂљВ¬Гўв‚¬Вќ NГѓЖ’Г†вЂ™O chame cs_consultar_profissionais):\n' +
      linhas +
      filtroHint +
      procRuleBlock;
  }
} catch (e) {
