      .join('\n');
    servicosBlock =
      '\n\n## SERVIГѓЖ’Гўв‚¬ВЎOS DISPONГѓЖ’Г‚ВЌVEIS (use estes servico_id ao chamar cs_agendar ГѓВўГўвЂљВ¬Гўв‚¬Вќ NГѓЖ’Г†вЂ™O chame cs_consultar_servicos):\n' +
      linhas;
  }
} catch (e) {
  /* sem serviГѓЖ’Г‚В§os */
}

const catalogBridge =
  servicosBlock && profBlock
    ? '\n\n## LEITURA DO CATГѓЖ’Г‚ВЃLOGO\n' +
      'Primeiro identifique o **servico_id** em **SERVIГѓЖ’Гўв‚¬ВЎOS DISPONГѓЖ’Г‚ВЌVEIS** conforme o pedido do cliente. ' +
      'Depois, em **PROFISSIONAIS DISPONГѓЖ’Г‚ВЌVEIS**, use sГѓЖ’Г‚Ві quem realiza esse serviГѓЖ’Г‚В§o (ver regra abaixo na lista de profissionais).\n'
    : '';

return [
  {
    json: {
      ...ctx,
      agent_instructions:
        (ctx.agent_instructions || '') + catalogBridge + servicosBlock + profBlock + procedimentoFromMsgBlock,
      _profissionais_pre_carregados: profBlock !== '',
      _servicos_pre_carregados: servicosBlock !== '',
      _procedimento_tool_hint: procedimentoToolHint,
