];

const rawIn = $input.first().json;
const item = { ...rawIn };
const ctx = $('Monta Contexto').first().json;
const inst = String($('Edit Fields1').first().json.instanceName || '').trim();
const nome = String(ctx.nome_cliente || 'Cliente').trim();
const out = String(rawIn.output ?? rawIn.text ?? rawIn.response ?? '').trim();
const tail = out.slice(-400);

const looksLikeMutation =
  /(reagendad|reagendamento|remarca(d|da|do)?|hor[aГѓЖ’Г‚ВЎ]rio\s+(alter|mud)|hor[aГѓЖ’Г‚ВЎ]rio\s+foi\s+alter|alterad[oa]\s+com\s+sucesso|atualizad[oa]\s+com\s+sucesso|foi\s+alterado|alterado\s+para|marcamos\s+para|nova\s+data|novo\s+hor[aГѓЖ’Г‚ВЎ]rio|agendad\w*\s+com\s+sucesso|agendamento[^\n]{0,120}sucesso|foi\s+confirmad[oa]|confirmad[oa][\s\S]{0,200}(consulta|sucesso)|confirmad[oa]\s+com\s+sucesso|ficou\s+agendad|est[ГѓЖ’Г‚ВЎa]\s+agendad|reservamos|cancelad|cancelamento)/i.test(
    out,
  );

let notify = null;

if (looksLikeMutation && ctx.clinic_id) {
  const remoteJid = String(ctx.remoteJid || '');
  const phoneForRpc = remoteJid.replace(/\D/g, '') || remoteJid;
  const SUPABASE_URL = 'https://xkwdwioawosthwjqijfb.supabase.co';
  const SUPABASE_KEY =
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inhrd2R3aW9hd29zdGh3anFpamZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NDUyNzUzMywiZXhwIjoyMDkwMTAzNTMzfQ._CoWPqn1bDqNRJ-g6EzGnqE86YI_LW5T_N6At3CPal4';

  let rpcRaw = null;
  try {
    rpcRaw = await $helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/rpc/n8n_cs_profissional_whatsapp_mudanca_recente',
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      body: JSON.stringify({ p_clinic_id: ctx.clinic_id, p_telefone: phoneForRpc }),
    });
  } catch {
    rpcRaw = null;
  }

  // $helpers.httpRequest pode devolver string, array ou objeto
  let rpc = rpcRaw;
  if (typeof rpcRaw === 'string') {
    try { rpc = JSON.parse(rpcRaw); } catch { rpc = null; }
  }
  if (Array.isArray(rpc)) {
    rpc = rpc[0] ?? null;
  }

  if (rpc && rpc.ok === true && rpc.profissional_whatsapp) {
    const num = String(rpc.profissional_whatsapp).replace(/\D/g, '');
    if (num.length >= 10) {
      function fmtData(s) {
        if (!s) return 'ГѓВўГўвЂљВ¬Гўв‚¬Вќ';
        const str = String(s).trim().slice(0, 10);
        const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(str);
        return m ? m[3] + '/' + m[2] + '/' + m[1] : str || 'ГѓВўГўвЂљВ¬Гўв‚¬Вќ';
      }
      function fmtHora(h) {
        if (h == null || h === '') return 'ГѓВўГўвЂљВ¬Гўв‚¬Вќ';
        const m = String(h).match(/^(\d{1,2}):(\d{2})/);
        return m ? m[1].padStart(2, '0') + ':' + m[2] : String(h);
      }
      function comDr(n, genero) {
        const s = String(n || '').trim();
        if (!s) return '';
        if (/^dra\.?\s/i.test(s)) return s;
        if (/^dr\.?\s/i.test(s)) return s;
        const g = String(genero || '').trim().toUpperCase();
        const pref = g === 'F' ? 'Dra.' : 'Dr.';
        return pref + ' ' + s;
      }
      function aberturaNova(np, gen) {
        const s = String(np || '').trim();
        if (!s) return 'VocГѓЖ’Г‚ВЄ tem um novo agendamento:';
        return comDr(s, gen) + ', vocГѓЖ’Г‚ВЄ tem um novo agendamento:';
      }
      function aberturaCancel(np, gen) {
        const s = String(np || '').trim();
        if (!s) return 'VocГѓЖ’Г‚ВЄ tem um cancelamento:';
        return comDr(s, gen) + ', vocГѓЖ’Г‚ВЄ tem um cancelamento:';
      }
      function aberturaResched(np, gen) {
        const s = String(np || '').trim();
        if (!s) return 'VocГѓЖ’Г‚ВЄ tem um reagendamento:';
        return comDr(s, gen) + ', vocГѓЖ’Г‚ВЄ tem um reagendamento:';
      }
      function formatTelBr(raw) {
        const s = String(raw || '').trim();
        if (!s) return '';
        const d = s.replace(/\D/g, '');
        if (d.length < 10) return '';
        let x = d;
        if (x.startsWith('55') && x.length >= 12) x = x.slice(2);
        if (x.length === 11) return '(' + x.slice(0, 2) + ') ' + x.slice(2, 7) + '-' + x.slice(7);
        if (x.length === 10) return '(' + x.slice(0, 2) + ') ' + x.slice(2, 6) + '-' + x.slice(6);
        if (s.startsWith('+')) return s;
        return '+' + d;
      }
      function linhasCliente(c, telFmt) {
        const lines = ['ГѓВ°Г…ВёГўв‚¬ЛњГ‚В¤ Cliente: ' + c];
        if (telFmt) lines.push('ГѓВ°Г…ВёГўв‚¬Е“Г…Вѕ Telefone: ' + telFmt);
        return lines;
      }
      function msgNovo(np, gen, c, sv, d, hr, telFmt) {
        return [aberturaNova(np, gen), '', 'ГѓВ°Г…ВёГ…ВёГ‚Вў Novo agendamento', '', ...linhasCliente(c, telFmt), 'ГѓВ°Г…ВёГўв‚¬Е“Г…вЂ™ ServiГѓЖ’Г‚В§o: ' + sv, 'ГѓВ°Г…ВёГўв‚¬Е“Гўв‚¬В¦ Data: ' + d, 'ГѓВ°Г…ВёГўв‚¬ВўГўв‚¬в„ў HorГѓЖ’Г‚ВЎrio: ' + hr].join("\n");
      }
      function msgCancel(np, gen, c, sv, d, hr, telFmt) {
        return [aberturaCancel(np, gen), '', 'ГѓВ°Г…ВёГўв‚¬ВќГ‚Вґ Cancelamento de agendamento', '', ...linhasCliente(c, telFmt), 'ГѓВ°Г…ВёГўв‚¬Е“Г…вЂ™ ServiГѓЖ’Г‚В§o: ' + sv, 'ГѓВ°Г…ВёГўв‚¬Е“Гўв‚¬В¦ Data: ' + d, 'ГѓВ°Г…ВёГўв‚¬ВўГўв‚¬в„ў HorГѓЖ’Г‚ВЎrio: ' + hr].join("\n");
      }
      function msgResched(np, gen, c, sv, d, hr, telFmt) {
        return [aberturaResched(np, gen), '', 'ГѓВ°Г…ВёГ…ВёГ‚ВЎ Reagendamento de agendamento', '', ...linhasCliente(c, telFmt), 'ГѓВ°Г…ВёГўв‚¬Е“Г…вЂ™ ServiГѓЖ’Г‚В§o: ' + sv, 'ГѓВ°Г…ВёГўв‚¬Е“Гўв‚¬В¦ Nova data: ' + d, 'ГѓВ°Г…ВёГўв‚¬ВўГўвЂћВў Novo horГѓЖ’Г‚ВЎrio: ' + hr].join("\n");
      }

      let row = null;
      try {
        const agId = rpc.agendamento_id;
        if (agId) {
          const rowRaw = await $helpers.httpRequest({
            method: 'GET',
            url: SUPABASE_URL + '/rest/v1/cs_agendamentos?id=eq.' + agId + '&select=nome_cliente,nome_procedimento,data_agendamento,horario,status,profissional_id,cliente_id',
            headers: {
              apikey: SUPABASE_KEY,
              Authorization: 'Bearer ' + SUPABASE_KEY,
              Accept: 'application/json',
            },
          });
          let rows = rowRaw;
          if (typeof rowRaw === 'string') {
            try { rows = JSON.parse(rowRaw); } catch (e) { rows = []; }
          }
          if (Array.isArray(rows) && rows[0]) row = rows[0];
        }
      } catch (e) {
        row = null;
      }

      let clienteTelFmt = '';
      if (row && row.cliente_id && ctx.clinic_id) {
        try {
          const cid = String(row.cliente_id).trim();
          const cRaw = await $helpers.httpRequest({
            method: 'GET',
            url: SUPABASE_URL + '/rest/v1/cs_clientes?id=eq.' + cid + '&clinic_id=eq.' + ctx.clinic_id + '&select=telefone',
            headers: {
              apikey: SUPABASE_KEY,
              Authorization: 'Bearer ' + SUPABASE_KEY,
              Accept: 'application/json',
            },
          });
          let crows = cRaw;
          if (typeof cRaw === 'string') {
            try { crows = JSON.parse(cRaw); } catch (e2) { crows = []; }
          }
          const tel0 = Array.isArray(crows) && crows[0] && crows[0].telefone != null
            ? String(crows[0].telefone).trim()
            : '';
          clienteTelFmt = formatTelBr(tel0);
        } catch (e3) {
          clienteTelFmt = '';
        }
      }
      // Fallback: usa remoteJid do contexto se telefone do cliente nГѓЖ’Г‚ВЈo resolveu
      if (!clienteTelFmt) {
        clienteTelFmt = formatTelBr(remoteJid) || '';
      }

      let profNome = '';
      let profGenero = '';
      if (row && row.profissional_id) {
        try {
          const prRaw = await $helpers.httpRequest({
            method: 'GET',
            url: SUPABASE_URL + '/rest/v1/cs_profissionais?id=eq.' + row.profissional_id + '&select=nome,gender',
            headers: {
              apikey: SUPABASE_KEY,
              Authorization: 'Bearer ' + SUPABASE_KEY,
              Accept: 'application/json',
            },
          });
          let prs = prRaw;
          if (typeof prRaw === 'string') {
            try { prs = JSON.parse(prRaw); } catch (e) { prs = []; }
          }
          if (Array.isArray(prs) && prs[0] && prs[0].nome) {
            profNome = String(prs[0].nome).trim();
            profGenero = prs[0].gender != null ? String(prs[0].gender).trim() : '';
          }
        } catch (e) {
          profNome = '';
          profGenero = '';
        }
      }

      const cliente = String((row && row.nome_cliente) || nome).trim() || 'Cliente';
      const serv = String((row && row.nome_procedimento) || 'Consulta').trim() || 'Consulta';
      const d = fmtData(row && row.data_agendamento);
      const h = fmtHora(row && row.horario);
      const stRow = String((row && row.status) || rpc.status_agendamento || '');

      const isCancel = stRow === 'cancelado' || /cancelad|cancelamento/i.test(out);
      const isResched =
        !isCancel &&
        /reagend|reagendamento|remarca|hor[aГѓЖ’Г‚ВЎ]rio\s+(alter|mud)|hor[aГѓЖ’Г‚ВЎ]rio\s+foi\s+alter|alterad[oa]\s+com\s+sucesso|atualizad[oa]\s+com\s+sucesso|foi\s+alterado|alterado\s+para|nova\s+data|novo\s+hor/i.test(out);

      let textBody;
      if (isCancel) textBody = msgCancel(profNome, profGenero, cliente, serv, d, h, clienteTelFmt);
      else if (isResched) textBody = msgResched(profNome, profGenero, cliente, serv, d, h, clienteTelFmt);
      else textBody = msgNovo(profNome, profGenero, cliente, serv, d, h, clienteTelFmt);

      const nomeProfTratado = comDr(profNome, profGenero) || 'Profissional';
      function clientePrimeiroNome(nc) {
        const t = String(nc || '').trim();
        if (!t || t.toLowerCase() === 'cliente') return 'Cliente';
        const parts = t.split(/\s+/).filter(Boolean);
        return parts[0] || t;
      }
      const cn = clientePrimeiroNome(cliente);
      let clientFormatted;
      if (isCancel) {
        clientFormatted = [
          'OlГѓЖ’Г‚ВЎ, ' + cn + '! Seu agendamento foi cancelado ГѓВўГ…вЂњГ‚ВЁ',
          '',
          'Seu atendimento foi cancelado com sucesso.',
          '',
          'ГѓВ°Г…ВёГўв‚¬Е“Г…вЂ™ ServiГѓЖ’Г‚В§o: ' + serv,
          'ГѓВ°Г…ВёГўв‚¬ЛњГ‚В¤ Profissional: ' + nomeProfTratado,
          'ГѓВ°Г…ВёГўв‚¬Е“Гўв‚¬В¦ Data: ' + d,
          'ГѓВ°Г…ВёГўв‚¬ВўГўв‚¬в„ў HorГѓЖ’Г‚ВЎrio: ' + h,
          '',
          'Se quiser remarcar, ГѓЖ’Г‚В© sГѓЖ’Г‚Ві responder esta mensagem.',
        ].join('\n');
      } else if (isResched) {
        clientFormatted = [
          'OlГѓЖ’Г‚ВЎ, ' + cn + '! Seu agendamento foi reagendado ГѓВўГ…вЂњГ‚ВЁ',
          '',
          'Seu novo horГѓЖ’Г‚ВЎrio foi atualizado com sucesso.',
          '',
          'ГѓВ°Г…ВёГўв‚¬Е“Г…вЂ™ ServiГѓЖ’Г‚В§o: ' + serv,
          'ГѓВ°Г…ВёГўв‚¬ЛњГ‚В¤ Profissional: ' + nomeProfTratado,
          'ГѓВ°Г…ВёГўв‚¬Е“Гўв‚¬В¦ Nova data: ' + d,
          'ГѓВ°Г…ВёГўв‚¬ВўГўв‚¬в„ў Novo horГѓЖ’Г‚ВЎrio: ' + h,
          '',
          'Se precisar de qualquer coisa, ГѓЖ’Г‚В© sГѓЖ’Г‚Ві responder esta mensagem.',
        ].join('\n');
      } else {
        clientFormatted = [
          'OlГѓЖ’Г‚ВЎ, ' + cn + '! Seu agendamento foi confirmado ГѓВўГ…вЂњГ‚ВЁ',
          '',
          'Seu atendimento estГѓЖ’Г‚ВЎ reservado com sucesso.',
          '',
          'ГѓВ°Г…ВёГўв‚¬Е“Г…вЂ™ ServiГѓЖ’Г‚В§o: ' + serv,
          'ГѓВ°Г…ВёГўв‚¬ЛњГ‚В¤ Profissional: ' + nomeProfTratado,
          'ГѓВ°Г…ВёГўв‚¬Е“Гўв‚¬В¦ Data: ' + d,
          'ГѓВ°Г…ВёГўв‚¬ВўГўв‚¬в„ў HorГѓЖ’Г‚ВЎrio: ' + h,
          '',
          'Se precisar de qualquer coisa, ГѓЖ’Г‚В© sГѓЖ’Г‚Ві responder esta mensagem.',
        ].join('\n');
      }
      item.output = clientFormatted;

      notify = {
        number: num,
        instanceName: inst,
        text: textBody,
      };
    }
  }
}

return [{ json: { ...item, _evolution_notify: notify } }];

