/**
 * Consolida fila Redis (Mensagem ou Mensagens) num ГѓЖ’Г‚Вєnico texto para o agente.
 * Dedup: ГѓЖ’Г‚Вєltima entrada por wppKeyId (Evolution); JSON idГѓЖ’Г‚ВЄntico sem id; texto repetido em sequГѓЖ’Г‚ВЄncia.
 * Devolve [] se vazio ГѓВўГўвЂљВ¬Гўв‚¬Вќ nГѓЖ’Г‚ВЈo avanГѓЖ’Г‚В§a para ResetaFila.
 */
const input = $input.first().json;
const raw = input.Mensagens ?? input.Mensagem;
let arr = [];
if (Array.isArray(raw)) {
  arr = raw;
} else if (raw != null && raw !== '') {
  arr = [raw];
}
if (arr.length === 0) {
  return [];
}
function parseCell(cell) {
  const s = typeof cell === 'string' ? cell : JSON.stringify(cell);
  try {
    const o = JSON.parse(s);
    const id =
      o && typeof o === 'object' && o.wppKeyId != null && o.wppKeyId !== ''
        ? String(o.wppKeyId)
        : null;
    const text =
      o && typeof o === 'object' && o.msg != null ? String(o.msg).trim() : s.trim();
    return { id, text, raw: s };
  } catch {
    return { id: null, text: s.trim(), raw: s };
  }
}
const parsed = arr.map(parseCell).filter((p) => p.text);
if (parsed.length === 0) {
  return [];
}
const lastIdxById = new Map();
for (let i = 0; i < parsed.length; i++) {
  const id = parsed[i].id;
  if (id) lastIdxById.set(id, i);
}
const byId = parsed.filter((p, i) => !p.id || lastIdxById.get(p.id) === i);
const seenRaw = new Set();
const uniqueRaw = [];
for (const p of byId) {
  if (seenRaw.has(p.raw)) continue;
  seenRaw.add(p.raw);
  uniqueRaw.push(p);
}
const lines = [];
for (const p of uniqueRaw) {
  if (lines.length > 0 && lines[lines.length - 1] === p.text) continue;
  lines.push(p.text);
}
const Mensagens = lines.join('\n');
if (!Mensagens.trim()) {
  return [];
}
return [{ json: { ...input, Mensagens } }];

const item = { ...$input.first().json };
// NOTA: Set node v3.4 dropa o body original, usar campos do Edit Fields1 diretamente
function digits(s) {
  return String(s ?? '').replace(/[^0-9]/g, '');
}
// Evento vem de item.event (setado pelo Edit Fields1 de body.event)
const rawEvent = item.event || '';
let event = String(rawEvent).trim().split('.').join('_').split('-').join('_').toUpperCase();
if (!event && item.numCliente) event = 'MESSAGES_UPSERT';

// instance_name vem de item.instanceName (setado pelo Edit Fields1 de body.instance)
const instance_name = String(item.instanceName || item.instanceId || '').trim();

// numero_clinica vem de item.numEmpresa (setado pelo Edit Fields1 de body.sender), so digitos
const numero_clinica = digits(item.numeroClinica || item.numEmpresa || '');

const whSrc = item._wh_source === 'test' ? 'test' : 'prod';
const _tenant = { event, instance_name, numero_clinica, wh_source: whSrc };
return [{ json: { ...item, _tenant } }];

const base = $('Code Normalizar Evolution Clinica').first().json;
const raw = $input.first().json;
const row = Array.isArray(raw) ? (raw[0] ?? {}) : raw;
const cenario =
  row.cenario ||
  (raw && typeof raw === 'object' && !Array.isArray(raw) && raw.message ? 'clinica_nao_encontrada' : null) ||
  'clinica_nao_encontrada';
return [{ json: { ...base, ...row, cenario } }];

return items.map(item => {
  const texto = item.json.answer || '';
  const match = texto.match(/https?:\/\/[^\s]+?\.(jpg|jpeg|png|gif)(\?[^\s]*)?/i);

  return {
    json: {
      imagem: match ? match[0] : null
    }
  };
});

// Dados da clГѓЖ’Г‚В­nica vГѓЖ’Г‚ВЄm de "Buscar Config Cl?nica" (nome real do node ГѓВўГўвЂљВ¬Гўв‚¬Вќ ? = ГѓЖ’Г‚В­ corrompido)
const clinicRaw = (() => {
  try {
    const r = $('Buscar Config Cl?nica').first().json;
    return Array.isArray(r) ? (r[0] || {}) : r;
  } catch { return {}; }
})();
const rawInstr = clinicRaw?.agent_instructions;
const clinic_name = clinicRaw?.name || '';

let agent_instructions = '';
let nome_agente = '';
let saudacao_novo = '';
let saudacao_retorno = '';
let instr_raw = {};

if (rawInstr) {
  try {
    const cfg = typeof rawInstr === 'string' ? JSON.parse(rawInstr) : rawInstr;
    nome_agente = cfg.nome_agente || '';
    saudacao_novo = cfg.saudacao_novo || '';
    saudacao_retorno = cfg.saudacao_retorno || '';
    instr_raw = cfg;
    const secoes = [
      { key: 'identidade', label: 'IDENTIDADE DO AGENTE' },
      { key: 'triagem',    label: 'TRIAGEM E URGENCIAS' },
      { key: 'tom',        label: 'TOM E LINGUAGEM' },
      { key: 'orientacoes',label: 'ORIENTACOES AO PACIENTE' },
      { key: 'transferir', label: 'QUANDO TRANSFERIR PARA HUMANO' },
      { key: 'outros',     label: 'OUTRAS INSTRUCOES' },
    ];
    agent_instructions = secoes
      .filter(s => typeof cfg[s.key] === 'string' && cfg[s.key].trim())
      .map(s => '### ' + s.label + '\n' + cfg[s.key].trim())
      .join('\n\n');
  } catch(e) { agent_instructions = String(rawInstr); }
}

const clientRow = (() => {
  try {
    const r = $('Get Cliente').first().json;
    return Array.isArray(r) ? (r[0] || {}) : r;
  } catch { return {}; }
})();
const nome_cliente = (clientRow?.nome || '').trim();
function _primeiroNomeDisplay(full) {
  const s = String(full || '').trim();
  if (!s) return '';
  const w = (s.split(/\s+/).filter(Boolean)[0] || '').trim();
  if (!w) return '';
  return w.charAt(0).toUpperCase() + w.slice(1).toLowerCase();
}
const nome_cliente_primeiro = nome_cliente ? _primeiroNomeDisplay(nome_cliente) : '';

let primeiro_contato = true;
try {
  const histRow = $('Check First Contact').first().json;
  const count = Number(histRow?.historico_count ?? 0);
  primeiro_contato = count === 0;
} catch { primeiro_contato = true; }

// [PATCH: normalize mensagem]
// Pega mensagem e normaliza: nunca deixa null/undefined/JSON-string chegar ao agent.
let _rawMsg;
try { _rawMsg = $('Edit Fields2').first().json.mensagem; } catch { _rawMsg = null; }
// Fallback 1: Edit Fields1.msg (texto extraГѓЖ’Г‚В­do do webhook)
if (_rawMsg == null || _rawMsg === '') {
  try { _rawMsg = $('Edit Fields1').first().json.msg || ''; } catch { _rawMsg = ''; }
}
// Fallback 2: campo conversation direto do webhook
if (!_rawMsg) {
  try { _rawMsg = $('Webhook').first().json.body?.data?.message?.conversation || ''; } catch { _rawMsg = ''; }
}
// Se ainda for JSON-string, extrai o texto
let mensagem = '';
if (typeof _rawMsg === 'string') {
  const _trimmed = _rawMsg.trim();
  if (_trimmed.startsWith('{') || _trimmed.startsWith('[')) {
    try {
      const _parsed = JSON.parse(_trimmed);
      mensagem = String(_parsed.msg || _parsed.mensagem || _parsed.text || _parsed.message || _parsed.Mensagens || _trimmed);
    } catch { mensagem = _trimmed; }
  } else {
    mensagem = _trimmed;
  }
} else if (_rawMsg != null) {
  mensagem = String(_rawMsg);
}
const clinic_id = $('Code merge webhook e resolucao').first().json.clinica_id;
const remoteJid = $('Webhook').first().json.body.data.key.remoteJid;
const instanceName = $('Edit Fields1').first().json.instanceName || '';

const _nowBR = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const _hr = _nowBR.getHours();
const saudacao_periodo = _hr >= 5 && _hr < 12 ? 'Bom dia' : _hr >= 12 && _hr < 18 ? 'Boa tarde' : 'Boa noite';
if (saudacao_novo) {
  saudacao_novo = saudacao_novo
    .replace(/{{periodo}}/g, saudacao_periodo)
    .replace(/{{name}}/g, nome_agente)
    .replace(/{{clinica}}/g, clinic_name);
}
if (saudacao_retorno) {
  saudacao_retorno = String(saudacao_retorno)
    .replace(/{{nome_cliente}}/g, nome_cliente)
    .replace(/{{primeiro_nome}}/g, nome_cliente_primeiro)
    .replace(/{{periodo}}/g, saudacao_periodo)
    .replace(/{{clinica}}/g, clinic_name)
    .replace(/{{name}}/g, nome_agente || '')
    .replace(/{{nome_agente}}/g, nome_agente || '');
}
if (agent_instructions) {
  agent_instructions = agent_instructions
    .replace(/{{name}}/g, nome_agente || '')
    .replace(/{{nome_agente}}/g, nome_agente || '')
    .replace(/{{agente}}/g, nome_agente || '')
    .replace(/{{clinica}}/g, clinic_name || '')
    .replace(/{{nome_clinica}}/g, clinic_name || '')
    .replace(/{{periodo}}/g, saudacao_periodo)
    .replace(/{{nome_cliente}}/g, nome_cliente || '')
    .replace(/{{primeiro_nome}}/g, nome_cliente_primeiro || '');
}

function _normHoursArr(v) {
  if (!Array.isArray(v)) return [];
  const s = new Set();
  for (const x of v) {
    const n = typeof x === 'number' ? x : parseInt(String(x), 10);
    if (Number.isFinite(n) && n >= 6 && n <= 22) s.add(n);
  }
  return [...s].sort((a,b)=>a-b);
}
function _fmtHourList(arr) {
  if (!arr.length) return 'conforme configuraГѓЖ’Г‚В§ГѓЖ’Г‚ВЈo no painel';
  return arr.map(h => String(h).padStart(2, '0') + ':00').join(', ');
}
const _wdH = _normHoursArr(clinicRaw.agenda_visible_hours);
const _sabOn = clinicRaw.sabado_aberto === true || clinicRaw.sabado_aberto === 'true' || clinicRaw.sabado_aberto === 1;
const _sabH = _normHoursArr(clinicRaw.sabado_agenda_hours);
let _horCal = '### HORГѓЖ’Г‚ВЃRIO DA CLГѓЖ’Г‚ВЌNICA (AGENDAMENTOS ГѓВўГўвЂљВ¬Гўв‚¬Вќ respeite estritamente)' + String.fromCharCode(10);
_horCal += '- Domingo: sem atendimento.' + String.fromCharCode(10);
_horCal += '- Dias ГѓЖ’Г‚Вєteis (segunda a sexta): blocos ' + _fmtHourList(_wdH) + '.' + String.fromCharCode(10);
if (!_sabOn) {
  _horCal += '- SГѓЖ’Г‚ВЎbado: sem atendimento.' + String.fromCharCode(10);
} else if (_sabH.length) {
  _horCal += '- SГѓЖ’Г‚ВЎbado: aberto ГѓВўГўвЂљВ¬Гўв‚¬Вќ blocos ' + _fmtHourList(_sabH) + '.' + String.fromCharCode(10);
} else {
  _horCal += '- SГѓЖ’Г‚ВЎbado: aberto ГѓВўГўвЂљВ¬Гўв‚¬Вќ mesmos blocos dos dias ГѓЖ’Г‚Вєteis.' + String.fromCharCode(10);
}
_horCal += 'NГѓЖ’Г‚ВЈo ofereГѓЖ’Г‚В§a horГѓЖ’Г‚ВЎrios em dias fechados nem fora dos blocos; use as tools para vagas reais.';
agent_instructions = (agent_instructions ? agent_instructions + String.fromCharCode(10,10) : '') + _horCal;

function _ymdSP(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}
function _brSP(d) {
  const day = String(d.getDate()).padStart(2, '0');
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const y = d.getFullYear();
  return day + '/' + m + '/' + y;
}
const _diasSem = ['domingo', 'segunda-feira', 'terГѓЖ’Г‚В§a-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sГѓЖ’Г‚ВЎbado'];
const cal_hoje_ymd = _ymdSP(_nowBR);
const cal_hoje_br = _brSP(_nowBR);
const cal_hoje_weekday = _diasSem[_nowBR.getDay()];
const _amanhaSP = new Date(_nowBR);
_amanhaSP.setDate(_amanhaSP.getDate() + 1);
const cal_amanha_ymd = _ymdSP(_amanhaSP);
const cal_amanha_br = _brSP(_amanhaSP);
const cal_amanha_weekday = _diasSem[_amanhaSP.getDay()];
const _calBlock =
  String.fromCharCode(10, 10) +
  '### CALENDГѓЖ’Г‚ВЃRIO OBRIGATГѓЖ’Гўв‚¬Е“RIO (America/Sao_Paulo)' +
  String.fromCharCode(10) +
  '- Hoje: ' +
  cal_hoje_weekday +
  ', ' +
  cal_hoje_br +
  ' ГѓВўГўвЂљВ¬Гўв‚¬Вќ YYYY-MM-DD: ' +
  cal_hoje_ymd +
  String.fromCharCode(10) +
  '- AmanhГѓЖ’Г‚ВЈ: ' +
  cal_amanha_weekday +
  ', ' +
  cal_amanha_br +
  ' ГѓВўГўвЂљВ¬Гўв‚¬Вќ YYYY-MM-DD: ' +
  cal_amanha_ymd +
  String.fromCharCode(10) +
  'Se o cliente disser AMANHГѓЖ’Г†вЂ™ ГѓВўГўв‚¬В Гўв‚¬в„ў data_solicitada na tool agd_cs_consultar_vagas DEVE ser ' +
  cal_amanha_ymd +
  '. Proibido usar outra data. Ao escrever ao cliente use esta data: ' +
  cal_amanha_br +
  '.' +
  String.fromCharCode(10) +
  'Se o cliente disser HOJE ГѓВўГўв‚¬В Гўв‚¬в„ў data_solicitada = ' +
  cal_hoje_ymd +
  '.';
agent_instructions = agent_instructions + _calBlock;

return [{ json: {
  mensagem,
  agent_instructions,
  nome_agente,
  clinic_name,
  nome_cliente,
  nome_cliente_primeiro,
  saudacao_novo,
  saudacao_retorno,
  saudacao_periodo,
  primeiro_contato,
  clinic_id,
  remoteJid,
  instanceName,
  instr_triagem:    instr_raw.triagem     || '',
  instr_faq:        instr_raw.orientacoes || '',
  instr_transferir: instr_raw.transferir  || '',
  instr_outros:     instr_raw.outros      || '',
  cal_hoje_ymd,
  cal_hoje_br,
  cal_hoje_weekday,
  cal_amanha_ymd,
  cal_amanha_br,
  cal_amanha_weekday,
} }];

const agentOutput = $input.first().json.output || '';
const montaCtx = $('Monta Contexto').first().json;
const userMsg = String(montaCtx.mensagem || '').trim();
const match = agentOutput.match(/\[ROTA:\s*(agendamento|faq|procedimentos|humano|concluido)\]/i);
let rota;
if (match) {
  rota = match[1].toLowerCase();
} else {
  const lower = agentOutput.toLowerCase();
  if (/(verificar|verifico|agendar|agendamento|horario|hor.rio|vagas|cancelar|reagendar|disponivel|dispon.vel|momento|encaminhar)/.test(lower)) {
    rota = 'agendamento';
  } else if (/(procedimento|funciona|o que .| como .| quando fazer|preparo|tratamento|explico)/.test(lower)) {
    rota = 'procedimentos';
  } else if (/(endere.o|funcionamento|conv.nio|pagamento|pix|localiz)/.test(lower)) {
    rota = 'faq';
  } else {
    rota = 'concluido';
  }
}
const shortAffirm =
  /^(sim|sii?m|ss|pode|confirmo|confirmado|isso|fechamos|ok|okay|claro|com certeza|pode ser|uhum|aham)\b/i.test(userMsg) &&
  userMsg.length < 56;
if (shortAffirm && (rota === 'concluido' || rota === 'procedimentos')) {
  rota = 'agendamento';
}
const output = agentOutput.replace(/\[ROTA:.*?\]/gi, '').trim();
return [{ json: { ...montaCtx, output, rota } }];

const ctx = $('Monta Contexto').first().json;
const msg = (ctx.instr_transferir || '').trim()
  || 'Um momento! Vou te transferir para um atendente humano. Em breve alguГѓЖ’Г‚В©m entrarГѓЖ’Г‚ВЎ em contato. ГѓВ°Г…ВёГ‹Е“Г…В ';
const instanceName = $('Code merge webhook e resolucao').first().json._tenant?.instance_name
  || ctx.instanceName
  || $('Edit Fields1').first().json.instanceName
  || $('Edit Fields1').first().json.instanceId
  || '';
return [{ json: {
  mensagem_handoff: msg,
  clinic_id: ctx.clinic_id,
  remoteJid: ctx.remoteJid,
  instanceName,
  telefone_numero: (ctx.remoteJid || '').split('@')[0].replace(/\D/g, ''),
} }];

